import java.time.*;

public class Main {
    public static void main(String[] args) {
        // 現在の日時を取得
        LocalDateTime now = LocalDateTime.now();

        // 2時間30分後を計算
        LocalDateTime after = now.plus(Duration.ofHours(2).plusMinutes(30));

        // 2時間30分後の日時を出力
        System.out.println("2時間30分後: " + after); // 出力例：2時間30分後: 2023-05-18T15:30:45.123
    }
}

import java.time.*;

public class Main {
    public static void main(String[] args) {
        // 指定した日時を作成
        LocalDateTime datetime1 = LocalDateTime.of(2023, 6, 10, 10, 0);
        LocalDateTime datetime2 = LocalDateTime.of(2023, 6, 15, 14, 0);

        // 2つの日時の間隔を計算
        Duration duration = Duration.between(datetime1, datetime2);

        // 日数と時間数を取得
        long days = duration.toDays();
        long hours = duration.toHours() % 24;

        // 間隔を出力
        System.out.println("間隔: " + days + "日" + hours + "時間"); // 出力例：間隔: 5日4時間
    }
}

import java.time.*;

public class Main {
    public static void main(String[] args) {
        // 指定した日時を作成
        ZonedDateTime datetime = ZonedDateTime.of(2023, 6, 10, 10, 0, 0, 0, ZoneId.of("Asia/Tokyo"));

        // ニューヨーク時間に変換
        ZonedDateTime newyorkDatetime = datetime.withZoneSameInstant(ZoneId.of("America/New_York"));

        // 変換後の日時を出力
        System.out.println("ニューヨーク時間: " + newyorkDatetime); // 出力例：ニューヨーク時間: 2023-06-09T21:00-04:00[America/New_York]
    }
}

